import 'dart:io';import 'brush.dart';void main(List<String>args){BrushPoint p(int x,int y)=>BrushPoint(x.toDouble(),y.toDouble());final points=[(500,520),(450,450),(390,395),(320,370),(250,370),(180,390),(130,450),(120,520),(155,585),(220,635),(300,650),(380,620),(440,570),(500,520),(560,465),(620,410),(700,370),(770,380),(830,420),(870,480),(875,545),(845,610),(790,660),(720,675),(650,655),(585,610),(540,560),(500,520)].map((v)=>p(v.$1,v.$2)).toList();if(Brush.buildRoundedDrawingPath([p(0,0),p(100,0),p(100,100)],40)!='M 0 0 L 55 0 Q 100 0 100 45 L 100 100')throw StateError('check');final input=args.isNotEmpty?args[0]:'assets/example.webp',output=args.length>1?args[1]:'generated/dart.svg';final svg=Brush.renderSvg(File(input).readAsBytesSync(),'image/webp',1000,1000,points,'🤝 best friends forever',const BrushOptions(magicGradient:true));File(output).parent.createSync(recursive:true);File(output).writeAsStringSync(svg);print('Wrote $output');}
